  `test_blee` varchar(3) DEFAULT NULL,
  `test_carba_A` varchar(3) DEFAULT NULL,
  `serotipo_invitro` varchar(60) DEFAULT NULL,
  `cevs` int DEFAULT NULL,
  `virulencia_galleria` int DEFAULT NULL,
  `fenot_hipermutador` varchar(15) DEFAULT NULL,
  PRIMARY KEY (`fenotipo_id`),
  UNIQUE KEY `aislado_id` (`aislado_id`),
  CONSTRAINT `fenotipo_ibfk_1` FOREIGN KEY (`aislado_id`) REFERENCES `metadata_general` (`aislado_id`)
